            aOrbiterA = ((aOrbiterA + aOrbiterE) + 0x99D05B994CDB3BF0ULL) + aPhaseCOrbiterUpdateSaltB[((aIndex + 18U)) & S_SALT1];
            aOrbiterC = (aOrbiterC ^ aOrbiterA) ^ 0xFA7C06F162375831ULL;
