            //
            aOrbiterJ = ((aOrbiterJ + aOrbiterI) + 0x6CC7B5EEC3689ECBULL) + aPhaseCOrbiterUpdateSaltC[(((31U - aIndex) + 6U)) & S_SALT1];
            aOrbiterG = ((aOrbiterG ^ aOrbiterJ) ^ 0xD0D2B9DBCCCBE3F0ULL) ^ aPhaseCOrbiterUpdateSaltA[(((31U - aIndex) + 7U)) & S_SALT1];
