            aOrbiterD = (aOrbiterD + aOrbiterI) + 0x893EA22FAE843CA0ULL;
            aOrbiterC = (aOrbiterC ^ aOrbiterD) ^ 0xB3AD329ED88F75B3ULL;
            aOrbiterC = RotL64((aOrbiterC * 0x5CAB1FCDF647E2E9ULL), 35U);
            //
            aOrbiterE = ((aOrbiterE + aOrbiterC) + 0x3B9A78B45AAAC192ULL) + aPhaseDOrbiterUpdateSaltC[((aIndex + 15U)) & S_SALT1];
            aOrbiterB = (aOrbiterB ^ aOrbiterE) ^ 0xE8C224B904305553ULL;
            aOrbiterB = RotL64((aOrbiterB * 0x22DE7A955541CCE9ULL), 47U);
            //
            aOrbiterH = (aOrbiterH + aOrbiterE) + 0xD1176B6D0251E33BULL;
            aOrbiterF = ((aOrbiterF ^ aOrbiterH) ^ 0x0DAEAF1A31A0AA96ULL) ^ aPhaseDOrbiterUpdateSaltA[((aIndex + 27U)) & S_SALT1];
            aOrbiterF = RotL64((aOrbiterF * 0x04A71EA6D1FA9AA3ULL), 19U);
            //
            aOrbiterC = (aOrbiterC + aOrbiterH) + 0xE41810519A13166FULL;
            aOrbiterK = (aOrbiterK ^ aOrbiterC) ^ 0x2C6570AEFA92BAB6ULL;
            aOrbiterK = RotL64((aOrbiterK * 0xC8BEB7850A4294ADULL), 53U);
            //
            aOrbiterK = ((aOrbiterK + aOrbiterF) + 0xF2CAF15A81286238ULL) + aPhaseDOrbiterUpdateSaltD[((aIndex + 8U)) & S_SALT1];
            aOrbiterI = (aOrbiterI ^ aOrbiterK) ^ 0xCB5CA7A51C4F03B2ULL;
            aOrbiterI = RotL64((aOrbiterI * 0x6CEE302A2C70BD35ULL), 23U);
