            aWandererI = aWandererI ^ ((RotL64(aPrevious, 3U) + aOrbiterC) + RotL64(aOrbiterH, 40U));
            aWandererG = aWandererG + ((((RotL64(aIngress, 27U) + aOrbiterH) + RotL64(aOrbiterI, 35U)) + RotL64(aCarry, 11U)) + aPhaseDWandererUpdateSaltB[(((31U - aIndex) + 23U)) & S_SALT1]);
            aWandererC = aWandererC ^ ((RotL64(aPrevious, 35U) + aOrbiterH) + RotL64(aOrbiterK, 57U));
            aWandererD = aWandererD + ((RotL64(aScatter, 47U) + RotL64(aOrbiterE, 11U)) + aOrbiterC);
            aWandererA = aWandererA ^ ((RotL64(aCross, 43U) + RotL64(aOrbiterF, 51U)) + aOrbiterI);
