            //
            aOrbiterC = (aWandererF + RotL64(aCross, 13U)) + 0x473B2BB5EF1C2B04ULL;
            aOrbiterJ = (aWandererC + RotL64(aIngress, 39U)) + 0x4626FB6E6422A2E5ULL;
            aOrbiterK = ((aWandererD + RotL64(aPrevious, 24U)) + RotL64(aCarry, 29U)) + 0x42A68D51AA72C88CULL;
            aOrbiterE = (aWandererE + RotL64(aScatter, 51U)) + 0x89792F99319734FBULL;
            aOrbiterG = (aWandererB + RotL64(aIngress, 29U)) + 0x1EB8D098F19102D0ULL;
            aOrbiterF = ((aWandererA + RotL64(aScatter, 35U)) + RotL64(aCarry, 11U)) + 0xDC88689256AABF63ULL;
            aOrbiterH = ((aWandererK + RotL64(aPrevious, 60U)) + 0xDDAF642B4A5E9867ULL) + aPhaseHOrbiterAssignSaltF[(((31U - aIndex) + 27U)) & S_SALT1];
            aOrbiterA = ((aWandererH + RotL64(aCross, 5U)) + 0x1E17A891C7BCAB95ULL) + aPhaseHOrbiterAssignSaltE[((aIndex + 10U)) & S_SALT1];
            aOrbiterI = ((aWandererI + RotL64(aIngress, 19U)) + RotL64(aCarry, 37U)) + 0x5940FCB7371B9A21ULL;
            //
            aOrbiterC = ((aOrbiterC + aOrbiterJ) + 0x7281ACFB7CD8CB1BULL) + aPhaseHOrbiterUpdateSaltA[((aIndex + 5U)) & S_SALT1];
            aOrbiterK = (aOrbiterK ^ aOrbiterC) ^ 0xE3416F6FA2173D79ULL;
            aOrbiterK = RotL64((aOrbiterK * 0xE24F5E4FBB3C571DULL), 35U);
            //
            aOrbiterJ = (aOrbiterJ + aOrbiterE) + 0x8CD99B9A38BBCC18ULL;
            aOrbiterG = ((aOrbiterG ^ aOrbiterJ) ^ 0x609E239D405F5D48ULL) ^ aPhaseHOrbiterUpdateSaltB[(((31U - aIndex) + 22U)) & S_SALT1];
            aOrbiterG = RotL64((aOrbiterG * 0x7C2A099F5D39D681ULL), 43U);
            //
            aOrbiterF = (aOrbiterF + aOrbiterH) + 0x5FB55FA75499B2FCULL;
            aOrbiterJ = (aOrbiterJ ^ aOrbiterF) ^ 0x8AF9D7B989382704ULL;
            aOrbiterJ = RotL64((aOrbiterJ * 0x32B10DB6C2D5A907ULL), 19U);
            //
            aOrbiterH = (aOrbiterH + aOrbiterA) + 0x6944885AB26D89A0ULL;
            aOrbiterE = (aOrbiterE ^ aOrbiterH) ^ 0x62D9D612136818C4ULL;
            aOrbiterE = RotL64((aOrbiterE * 0x07EAF9E078487155ULL), 53U);
            //
            aOrbiterI = (aOrbiterI + aOrbiterK) + 0x75D761304AD30A61ULL;
            aOrbiterF = (aOrbiterF ^ aOrbiterI) ^ 0x49D707CBDEC7977FULL;
            aOrbiterF = RotL64((aOrbiterF * 0x94CEBBD209E2485DULL), 57U);
            //
            aOrbiterE = (aOrbiterE + aOrbiterC) + 0x3702EB19CF592ED7ULL;
            aOrbiterI = ((aOrbiterI ^ aOrbiterE) ^ 0x8BEFCDD4198B79D5ULL) ^ aPhaseHOrbiterUpdateSaltF[(((31U - aIndex) + 24U)) & S_SALT1];
            aOrbiterI = RotL64((aOrbiterI * 0x88B2591A409B82F7ULL), 47U);
            //
            aOrbiterK = (aOrbiterK + aOrbiterG) + 0x3661F52A32ACB6B3ULL;
            aOrbiterH = ((aOrbiterH ^ aOrbiterK) ^ 0x35A3BC4A6619D6C7ULL) ^ aPhaseHOrbiterUpdateSaltC[(((31U - aIndex) + 29U)) & S_SALT1];
            aOrbiterH = RotL64((aOrbiterH * 0x9F212E61480EA4F7ULL), 27U);
            //
            aOrbiterA = (aOrbiterA + aOrbiterF) + 0xDA0701C0F398C3C5ULL;
            aOrbiterC = (aOrbiterC ^ aOrbiterA) ^ 0xAC11A6D02C8C7986ULL;
            aOrbiterC = RotL64((aOrbiterC * 0x8D7CE8396D999AABULL), 39U);
            //
            aOrbiterG = (aOrbiterG + aOrbiterI) + 0x0FD44463D7B0FE56ULL;
            aOrbiterA = (aOrbiterA ^ aOrbiterG) ^ 0xF44DDADC1E990CBBULL;
            aOrbiterA = RotL64((aOrbiterA * 0xD1CAE9B7DB207035ULL), 5U);
            //
            aIngress = RotL64(aOrbiterE, 19U) ^ aOrbiterA;
            aIngress = aIngress + (RotL64(aOrbiterF, 29U) ^ aOrbiterC);
